const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x0f0f14);this.g=H-80;this.p=this.add.rectangle(80,this.g,22,22,0x7cff8b);this.physics.add.existing(this.p);this.p.body.setGravityY(850);this.obs=this.physics.add.group();this.s=0;this.over=false;this.t=this.add.text(10,10,'Score:0');this.input.on('pointerdown',()=>this.jump());this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');this.time.addEvent({delay:900,loop:true,callback:()=>{if(this.over)return;const o=this.add.rectangle(W+20,this.g,24,24,0xff6b6b);this.physics.add.existing(o);o.body.setVelocityX(-250);this.obs.add(o);}});this.physics.add.overlap(this.p,this.obs,()=>this.end());}jump(){if(this.p.y>=this.g-1)this.p.body.setVelocityY(-360);}end(){if(this.over)return;this.over=true;this.add.text(W/2,H/2,'GAME OVER\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.over)return;if(this.c.up.isDown)this.jump();this.s++;this.t.setText('Score:'+((this.s/10)|0));this.obs.getChildren().forEach(o=>o.x<-30&&o.destroy());}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});